<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@FullName" @onchange="e => FullName = (string)e.Value!" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" value="@Email" @onchange="e => Email = (string)e.Value!" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Phone" @onchange="e => Phone = (string)e.Value!" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Address" @onchange="e => Address = (string)e.Value!" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public PersonalInfo? Info { get; set; }
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;

    private string FullName { get; set; } = "";
    private string Email { get; set; } = "";
    private string Phone { get; set; } = "";
    private string Address { get; set; } = "";
    private string? ErrorMessage { get; set; }
    private bool IsValidating { get; set; }

    protected override void OnParametersSet()
    {
        if (Info is not null)
        {
            FullName = Info.FullName;
            Email = Info.Email;
            Phone = Info.Phone;
            Address = Info.Address;
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email) ||
            string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }

            await OnNext.InvokeAsync(new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()));
        }
        finally
        {
            IsValidating = false;
        }
    }
}
"}

{"path": "/tmp/sv-1df0022b95284031838ee1b919575af7/Components/JobApplication/WorkHistoryStep.razor", "file_text": "@using sv_1df0022b95284031838ee1b919575af7.Models

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index"
                   ShowRemoveButton="Entries.Count > 1"
                   OnEntryChanged="entry => UpdateEntry(index, entry)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public WorkHistory? History { get; set; }
    [Parameter] public EventCallback<WorkHistory> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<WorkEntry> Entries { get; set; } = new();
    private string? ErrorMessage { get; set; }

    protected override void OnParametersSet()
    {
        if (History is not null && History.Entries.Count > 0)
        {
            Entries = History.Entries.ToList();
        }
        else if (Entries.Count == 0)
        {
            Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
        }
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private void UpdateEntry(int index, WorkEntry entry)
    {
        Entries[index] = entry;
    }

    private void HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each work entry must have a company name and job title.";
                return;
            }
        }

        OnNext.InvokeAsync(new WorkHistory(Entries.ToList()));
    }
}
"}

{"path": "/tmp/sv-1df0022b95284031838ee1b919575af7/Components/JobApplication/ReferencesStep.razor", "file_text": "@using sv_1df0022b95284031838ee1b919575af7.Models

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]"
                   ShowRemoveButton="References.Count > 2"
                   OnReferenceChanged="r => UpdateReference(index, r)"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<Reference>? ExistingReferences { get; set; }
    [Parameter] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<Reference> References { get; set; } = new();
    private string? ErrorMessage { get; set; }

    protected override void OnParametersSet()
    {
        if (ExistingReferences is not null && ExistingReferences.Count > 0)
        {
            References = ExistingReferences.ToList();
        }
        else if (References.Count == 0)
        {
            References.Add(new Reference("", "", "", ""));
            References.Add(new Reference("", "", "", ""));
        }
    }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new Reference("", "", "", ""));
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private void UpdateReference(int index, Reference reference)
    {
        References[index] = reference;
    }

    private void HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                ErrorMessage = "Each reference must have at least a name and email.";
                return;
            }
        }

        OnNext.InvokeAsync(References.ToList());
    }
}
"}

{"path": "/tmp/sv-1df0022b95284031838ee1b919575af7/Components/JobApplication/CoverLetterStep.razor", "file_text": "<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" @oninput="OnInput" value="@Text"></textarea>
    <div class="form-text text-end">@Text.Length / @MaxLength characters</div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string? ExistingText { get; set; }
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string Text { get; set; } = "";

    protected override void OnParametersSet()
    {
        if (ExistingText is not null)
            Text = ExistingText;
    }

    private void OnInput(ChangeEventArgs e)
    {
        var value = (string?)e.Value ?? "";
        Text = value.Length > MaxLength ? value[..MaxLength] : value;
    }

    private void HandleNext()
    {
        OnNext.InvokeAsync(Text);
    }
}
"}

{"path": "/tmp/sv-1df0022b95284031838ee1b919575af7/Components/JobApplication/ReviewStep.razor", "file_text": "@using sv_1df0022b95284031838ee1b919575af7.Models

<h4 class="mb-3">Review & Submit</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <h5>Application Submitted Successfully!</h5>
        <p>Your application ID is: <strong>@ApplicationId</strong></p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    @* Personal Info Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    @* Work History Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in Work.Entries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <h6>@entry.Title at @entry.Company</h6>
                    <p class="text-muted mb-1">
                        @entry.StartDate.ToString("MMM yyyy") &ndash; @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </p>
                    <p class="mb-0">@entry.Description</p>
                </div>
            }
        </div>
    </div>

    @* References Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    @* Cover Letter Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public WorkHistory Work { get; set; } = default!;
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private bool IsSubmitting { get; set; }
    private bool IsSubmitted { get; set; }
    private int ApplicationId { get; set; }
    private string? ErrorMessage { get; set; }

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;

        try
        {
            var application = new JobApplication(Personal, Work, References, CoverLetter);
            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}
"}

