@page "/apply"
@using sv_1df0022b95284031838ee1b919575af7.Models
@using sv_1df0022b95284031838ee1b919575af7.Components.JobApplication
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="@currentStep" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Info="@personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="HandlePersonalNext" />
            break;
        case 1:
            <WorkHistoryStep History="@workHistory"
                             OnNext="HandleWorkNext"
                             OnBack="HandleBack" />
            break;
        case 2:
            <ReferencesStep ExistingReferences="@references"
                            OnNext="HandleReferencesNext"
                            OnBack="HandleBack" />
            break;
        case 3:
            <CoverLetterStep ExistingText="@coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="HandleBack" />
            break;
        case 4:
            <ReviewStep Personal="@personalInfo!"
                        Work="@workHistory!"
                        References="@references!"
                        CoverLetter="@(coverLetter ?? "")"
                        ApplicationService="ApplicationService"
                        OnEdit="GoToStep"
                        OnBack="HandleBack" />
            break;
    }
</div>

@code {
    private int currentStep;
    private PersonalInfo? personalInfo;
    private WorkHistory? workHistory;
    private List<Reference>? references;
    private string? coverLetter;

    private void GoToStep(int step)
    {
        if (step < currentStep)
            currentStep = step;
    }

    private void HandleBack() => currentStep--;

    private void HandlePersonalNext(PersonalInfo info)
    {
        personalInfo = info;
        currentStep = 1;
    }

    private void HandleWorkNext(WorkHistory history)
    {
        workHistory = history;
        currentStep = 2;
    }

    private void HandleReferencesNext(List<Reference> refs)
    {
        references = refs;
        currentStep = 3;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        currentStep = 4;
    }
}

